  /** 缓冲区属性 */
  function bufferAttribute(array: any, type: string, stride?: number, offset?: number): ShaderNodeObject<Node>;
  /** 实例索引 */
  const instanceIndex: ShaderNodeObject<Node>;
  /** 顶点索引 */
  const vertexIndex: ShaderNodeObject<Node>;

  // ======================== 数学运算节点 ========================

  function abs(a: any): ShaderNodeObject<Node>;
  function acos(a: any): ShaderNodeObject<Node>;
  function asin(a: any): ShaderNodeObject<Node>;
  function atan(a: any): ShaderNodeObject<Node>;
  function atan2(a: any, b: any): ShaderNodeObject<Node>;
  function ceil(a: any): ShaderNodeObject<Node>;
  function clamp(a: any, low?: any, high?: any): ShaderNodeObject<Node>;
  function cos(a: any): ShaderNodeObject<Node>;
  function cross(a: any, b: any): ShaderNodeObject<Node>;
  function degrees(a: any): ShaderNodeObject<Node>;
  function distance(a: any, b: any): ShaderNodeObject<Node>;
  function dot(a: any, b: any): ShaderNodeObject<Node>;
  function exp(a: any): ShaderNodeObject<Node>;
  function exp2(a: any): ShaderNodeObject<Node>;
  function faceForward(n: any, i: any, nRef: any): ShaderNodeObject<Node>;
  function floor(a: any): ShaderNodeObject<Node>;
  function fract(a: any): ShaderNodeObject<Node>;
  function inverseSqrt(a: any): ShaderNodeObject<Node>;
  function length(a: any): ShaderNodeObject<Node>;
  function log(a: any): ShaderNodeObject<Node>;
  function log2(a: any): ShaderNodeObject<Node>;
  function max(a: any, b: any): ShaderNodeObject<Node>;
  function min(a: any, b: any): ShaderNodeObject<Node>;
  function mix(a: any, b: any, t: any): ShaderNodeObject<Node>;
  function mod(a: any, b: any): ShaderNodeObject<Node>;
  function negate(a: any): ShaderNodeObject<Node>;
