declare namespace VD {
  /** 渲染器 */
  class Render {
    /** 渲染器实例 */
    renderer: THREE.WebGPURenderer;
    /** 场景 */
    scene: THREE.Scene;
    /** 当前相机 */
    camera: THREE.Camera;

    /** 执行渲染 */
    render(): void;
    /** 调整渲染器尺寸 */
    resize(): void;
  }

  /** 引擎核心 */
  class Core {
    /** 容器 DOM 元素 */
    container: HTMLDivElement;
    /** 渲染器 */
    render: Render;
    /** 计时器 */
    timer: THREE.Timer;

    /** 挂载到 DOM */
    mount(root: HTMLDivElement): void;
    /** 卸载 */
    unmount(): void;
    /** 开始渲染循环 */
    run(): void;
    /** 停止渲染循环 */
    stop(): void;
    /** 调整尺寸 */
    resize(): void;
  }

  /** 组件基类，脚本需继承此类 */
  class Component {
    /** 组件挂载的 3D 对象 */
    object: THREE.Object3D;
    /** 引擎核心 */
    core: Core;

    constructor(object: THREE.Object3D);

    /** 组件挂载时调用 */
    onMount(core: VD.Core): void;
    /** 组件卸载时调用 */
    onUnmount(core: VD.Core): void;
    /** 窗口尺寸改变时调用 */
    onResize(core: VD.Core): void;
    /** 场景每帧更新（每帧） */
    onUpdate(core: VD.Core): void;
    /** 场景渲染前调用（每帧） */
    onRenderBefore(core: VD.Core): void;
    /** 场景渲染后调用（每帧） */
    onRenderAfter(core: VD.Core): void;
    /** 组件销毁时调用 */
    onDestroy(): void;
  }

  /** 为对象添加组件 */
  function addComponent(object: THREE.Object3D, component: Component): void;
  /** 从对象移除组件 */
  function removeComponent(object: THREE.Object3D, component: Component): void;
  /** 按类名获取对象上的组件 */
  function getComponent(object: THREE.Object3D, component: new (object: THREE.Object3D) => Component): Component | undefined;
  /** 按条件查找对象上的组件 */
  function findComponent(object: THREE.Object3D, predicate: (component: Component) => boolean): Component | undefined;
}
